#include <esp_system.h>
#include <esp_http_client.h>
#include <esp_ota.h>

void firmwareUpdate(const char* url) {
    // Download the firmware binary over HTTP
    esp_http_client_config_t config = {
        .url = url,
        .event_handler = NULL,
        .buffer_size = 1024
    };
    esp_http_client_handle_t client = esp_http_client_init(&config);
    esp_http_client_set_method(client, HTTP_METHOD_GET);
    esp_http_client_set_header(client, "User-Agent", "ESP32 Firmware Update");

    // Save the firmware binary to flash memory
    uint8_t* buffer = (uint8_t*)malloc(config.buffer_size);
    size_t total_size = 0;
    while (true) {
        esp_err_t err = esp_http_client_read(client, buffer, config.buffer_size);
        if (err != ESP_OK) {
            break;
        }
        total_size += config.buffer_size;
        esp_ota_write(0, buffer, total_size);
    }
    free(buffer);

    // Reboot the device to apply the update
    esp_restart();
}